using System.Collections;
using UnityEngine;
using UnityEngine.Events;

/// <summary>
/// Plataforma que cai quando o player pousar nela.
///
/// Fluxo:
/// 1. Idle — plataforma quieta. O player pode pousar e ficar em cima.
/// 2. Ao detectar o player em cima (OnCollisionEnter2D), começa a contar
///    <see cref="fallDelay"/> segundos (sacudindo, se <see cref="shakeDuration"/>
///    > 0 e <see cref="shakeAmount"/> > 0).
/// 3. Ao fim do delay, cai a <see cref="fallSpeed"/> m/s (Rigidbody2D
///    cinemático — gravidade ignorada, velocidade constante).
/// 4. Ao atingir o <see cref="groundLayer"/> (ou o <see cref="fallDistance"/>
///    máximo), pára.
/// 5. Se <see cref="respawnDelay"/> > 0: volta à posição original após esse
///    tempo. Se == 0: só volta ao recarregar a área (o designer pode chamar
///    <see cref="Respawn"/> manualmente, ex.: via UnityEvent de uma porta).
/// </summary>
[RequireComponent(typeof(Rigidbody2D), typeof(Collider2D))]
[DisallowMultipleComponent]
public class FallingPlatform : MonoBehaviour
{
    // ── Queda ─────────────────────────────────────────────────────────────────

    [Header("Temporização da Queda")]
    [Tooltip("Segundos entre o player pousar e a plataforma começar a cair. Durante este tempo a plataforma vibra (se shakeAmount > 0). Padrão: 0.6 s.")]
    [Min(0f)] public float fallDelay = 0.6f;

    [Tooltip("Velocidade de queda (m/s). A plataforma cai a esta velocidade constante (sem aceleração por gravidade). Padrão: 8 m/s.")]
    [Min(0.5f)] public float fallSpeed = 8f;

    [Tooltip("Distância máxima de queda (m). Se 0, só para ao colidir com 'groundLayer'.")]
    [Min(0f)] public float fallDistance = 0f;

    [Tooltip("Layer(s) do chão/blocos que param a queda. Se vazio, a plataforma pára apenas ao atingir 'fallDistance' (ou nunca, se fallDistance == 0).")]
    public LayerMask groundLayer;

    // ── Sacudidela (feedback antes da queda) ──────────────────────────────────

    [Header("Sacudidela (feedback visual)")]
    [Tooltip("Duração (segundos) da sacudidela. Deve ser <= fallDelay.")]
    [Min(0f)] public float shakeDuration = 0.4f;

    [Tooltip("Amplitude (m) da sacudidela horizontal antes de cair. 0 = sem sacudidela.")]
    [Min(0f)] public float shakeAmount = 0.04f;

    // ── Respawn ────────────────────────────────────────────────────────────────

    [Header("Respawn")]
    [Tooltip("Segundos após parar até a plataforma voltar à posição original e ficar Idle novamente. Padrão: 3 s.\n\n0 = NÃO volta automaticamente — permanece caída até ser reactivada externamente (ex.: entrar novamente na área ou chamar Respawn() via UnityEvent).")]
    [Min(0f)] public float respawnDelay = 3f;

    // ── Dano ──────────────────────────────────────────────────────────────────

    [Header("Dano de Esmagar (opcional)")]
    [Tooltip("Dano causado ao player SE ele ficar entre a plataforma e o chão (esmagar). 0 = sem dano de esmagar.")]
    [Min(0)] public int crushDamage = 0;

    // ── Áudio / Eventos ───────────────────────────────────────────────────────

    [Header("Áudio / Eventos")]
    [SerializeField] private AudioClip shakeSfx;
    [SerializeField] private AudioClip impactSfx;
    public UnityEvent onFallStart;
    public UnityEvent onLand;
    public UnityEvent onRespawn;

    // ── Internos ───────────────────────────────────────────────────────────────

    private Rigidbody2D rb;
    private Vector3 originPosition;

    private enum State { Idle, Counting, Falling, Resting }
    private State state = State.Idle;

    private bool playerOnPlatform;

    private void Awake()
    {
        rb = GetComponent<Rigidbody2D>();
        rb.bodyType = RigidbodyType2D.Kinematic;
        rb.gravityScale = 0f;

        originPosition = transform.position;
    }

    private void FixedUpdate()
    {
        if (state != State.Falling) return;

        rb.MovePosition(rb.position + Vector2.down * fallSpeed * Time.fixedDeltaTime);

        // Verifica colisão com chão.
        if (groundLayer.value != 0)
        {
            float checkDist = fallSpeed * Time.fixedDeltaTime + 0.05f;
            var hit = Physics2D.BoxCast(rb.position, GetColliderSize() * 0.9f, 0f, Vector2.down, checkDist, groundLayer);
            if (hit.collider != null)
            {
                Land();
                return;
            }
        }

        // Distância máxima de queda.
        if (fallDistance > 0f && Vector3.Distance(transform.position, originPosition) >= fallDistance)
            Land();
    }

    private void OnCollisionEnter2D(Collision2D col)
    {
        if (state != State.Idle) return;
        if (!col.gameObject.CompareTag("Player")) return;

        // Apenas conta se o player chegou de cima.
        foreach (var contact in col.contacts)
        {
            if (contact.normal.y < -0.5f) // normal aponta para cima = player aterrou
            {
                playerOnPlatform = true;
                StartCoroutine(FallSequence());
                return;
            }
        }
    }

    private void OnCollisionExit2D(Collision2D col)
    {
        if (col.gameObject.CompareTag("Player"))
            playerOnPlatform = false;
    }

    private IEnumerator FallSequence()
    {
        state = State.Counting;
        onFallStart?.Invoke();
        AudioManager.Instance?.PlaySE(shakeSfx);

        // Sacudidela.
        if (shakeAmount > 0f && shakeDuration > 0f)
        {
            float elapsed = 0f;
            Vector3 basePos = transform.position;
            while (elapsed < Mathf.Min(shakeDuration, fallDelay))
            {
                float offsetX = Mathf.Sin(elapsed * 60f) * shakeAmount;
                transform.position = basePos + new Vector3(offsetX, 0f, 0f);
                elapsed += Time.deltaTime;
                yield return null;
            }
            transform.position = basePos;
        }

        // Aguarda o restante delay.
        float remaining = fallDelay - Mathf.Min(shakeDuration, fallDelay);
        if (remaining > 0f) yield return new WaitForSeconds(remaining);

        if (state != State.Counting) yield break; // cancelado (ex.: player saiu, reset externo)

        state = State.Falling;
    }

    private void Land()
    {
        state = State.Resting;
        rb.linearVelocity = Vector2.zero;

        // Crush damage: se player ainda estiver em cima (esmagado).
        if (crushDamage > 0 && playerOnPlatform)
        {
            var playerT = PlayerLocator.Find();
            if (playerT != null)
            {
                var info = new DamageInfo(crushDamage, DamageType.Hazard, transform.position, 0f, null, ignoreDefense: true);
                PlayerCombat.TryDamagePlayer(playerT, info);
            }
        }

        AudioManager.Instance?.PlaySE(impactSfx);
        onLand?.Invoke();

        if (respawnDelay > 0f)
            StartCoroutine(RespawnAfterDelay());
    }

    private IEnumerator RespawnAfterDelay()
    {
        yield return new WaitForSeconds(respawnDelay);
        Respawn();
    }

    /// <summary>
    /// Volta à posição original e fica Idle. Pode ser chamado externamente
    /// (ex.: trigger de entrada na sala) quando <see cref="respawnDelay"/> == 0.
    /// </summary>
    public void Respawn()
    {
        StopAllCoroutines();
        state = State.Idle;
        playerOnPlatform = false;
        transform.position = originPosition;
        rb.linearVelocity = Vector2.zero;
        onRespawn?.Invoke();
    }

    private Vector2 GetColliderSize()
    {
        var c = GetComponent<Collider2D>();
        if (c is BoxCollider2D box) return box.size;
        if (c is CapsuleCollider2D cap) return cap.size;
        return new Vector2(1f, 0.2f);
    }

    private void OnDrawGizmosSelected()
    {
        if (fallDistance <= 0f) return;

        Gizmos.color = new Color(1f, 0.5f, 0f, 0.5f);
        Vector3 dest = (Application.isPlaying ? transform.position : (Vector3)((Vector2)transform.position)) + Vector3.down * fallDistance;
        Gizmos.DrawLine(transform.position, dest);
        Gizmos.DrawWireSphere(dest, 0.15f);
    }
}
